task.output_schema:

# {episode_id}-estimate.yaml
# Auto-generated by cost-estimate task (T2)

episode_id: "{episode_id}"
episode_title: "{episode_title}"
generated_at: "{ISO-8601 timestamp}"
ssd_source: "episodes/{episode_id}/ssd/scene-spec.yaml"
pricing_source: "_config/pricing.yaml"
resolution_profile: "{active_resolution_profile}"
veo_model: "{veo_model}"
retake_budget_percent: {int}

summary:
  total_scenes: {int}
  total_duration_seconds: {float}
  base_cost: {float}
  retake_buffer: {float}
  estimated_total: {float}
  currency: "USD"

per_scene_breakdown:
  - scene_id: "{scene_id}"
    title: "{scene_title}"
    tool: "{tool_name}"
    model: "{model_name}"
    resolution: "{resolution}"
    duration_seconds: {float}
    call_count: {int}
    cost_per_unit: {float}
    scene_cost: {float}

tool_totals:
  - tool: "{tool_name}"
    total_calls: {int}
    total_cost: {float}
    percentage_of_total: {float}

retake_buffer:
  percent: {int}
  amount: {float}

resolution_alternatives:
  - tier: "draft"
    base_cost: {float}
    retake_buffer: {float}
    total: {float}
    savings_vs_current: {float}
  - tier: "standard"
    base_cost: {float}
    retake_buffer: {float}
    total: {float}
    savings_vs_current: {float}
  - tier: "hd"
    base_cost: {float}
    retake_buffer: {float}
    total: {float}
    savings_vs_current: {float}
  - tier: "4k"
    base_cost: {float}
    retake_buffer: {float}
    total: {float}
    savings_vs_current: {float}

warnings: []
